#!/bin/bash\n\n# Naar & Noor - Development Startup Script\n# This script starts both frontend and backend applications\n\necho \"🍽️  Naar & Noor - Development Environment\"\necho \"=========================================\"\necho \"\"\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nBLUE='\\033[0;34m'\nNC='\\033[0m' # No Color\n\n# Check prerequisites\necho \"${BLUE}Checking prerequisites...${NC}\"\n\n# Check Node.js\nif ! command -v node &> /dev/null; then\n    echo \"${RED}❌ Node.js is not installed${NC}\"\n    echo \"Please install Node.js 18+ from https://nodejs.org/\"\n    exit 1\nfi\necho \"${GREEN}✓ Node.js $(node --version)${NC}\"\n\n# Check npm\nif ! command -v npm &> /dev/null; then\n    echo \"${RED}❌ npm is not installed${NC}\"\n    exit 1\nfi\necho \"${GREEN}✓ npm $(npm --version)${NC}\"\n\n# Check .NET\nif ! command -v dotnet &> /dev/null; then\n    echo \"${RED}❌ .NET SDK is not installed${NC}\"\n    echo \"Please install .NET 8.0 SDK from https://dotnet.microsoft.com/download\"\n    exit 1\nfi\necho \"${GREEN}✓ .NET $(dotnet --version)${NC}\"\n\necho \"\"\necho \"${BLUE}Starting applications...${NC}\"\necho \"\"\n\n# Start backend\necho \"${YELLOW}Starting Backend (Terminal 1)...${NC}\"\necho \"Command: cd api-server && dotnet run --project src/NaarNoor.API/NaarNoor.API.csproj\"\necho \"\"\n\ncd api-server\n\n# Check if packages are restored\nif [ ! -d \"obj\" ]; then\n    echo \"${BLUE}Restoring NuGet packages...${NC}\"\n    dotnet restore\n    echo \"\"\nfi\n\n# Start backend in background\ndotnet run --project src/NaarNoor.API/NaarNoor.API.csproj &\nBACKEND_PID=$!\n\necho \"${GREEN}Backend started (PID: $BACKEND_PID)${NC}\"\necho \"Waiting for backend to be ready...\"\nsleep 5\n\n# Check if backend is running\nif ! kill -0 $BACKEND_PID 2>/dev/null; then\n    echo \"${RED}❌ Backend failed to start${NC}\"\n    exit 1\nfi\n\necho \"${GREEN}✓ Backend is running at http://localhost:5000${NC}\"\necho \"\"\n\n# Start frontend\necho \"${YELLOW}Starting Frontend (Terminal 2)...${NC}\"\necho \"Command: cd naar-noor && npm run dev\"\necho \"\"\n\ncd ../naar-noor\n\n# Check if node_modules exists\nif [ ! -d \"node_modules\" ]; then\n    echo \"${BLUE}Installing npm packages...${NC}\"\n    npm install\n    echo \"\"\nfi\n\n# Start frontend\nnpm run dev &\nFRONTEND_PID=$!\n\necho \"${GREEN}Frontend started (PID: $FRONTEND_PID)${NC}\"\necho \"\"\n\necho \"${GREEN}=========================================${NC}\"\necho \"${GREEN}✓ Both applications are running!${NC}\"\necho \"${GREEN}=========================================${NC}\"\necho \"\"\necho \"${BLUE}Frontend:${NC}  http://localhost:4200\"\necho \"${BLUE}Backend:${NC}   http://localhost:5000\"\necho \"${BLUE}Swagger:${NC}   http://localhost:5000/swagger\"\necho \"${BLUE}Health:${NC}    http://localhost:5000/health\"\necho \"\"\necho \"${YELLOW}Press Ctrl+C to stop both applications${NC}\"\necho \"\"\n\n# Wait for both processes\nwait\n